messages.content:
Analyze the following JSON PRD and design resource access interfaces.

JSON PRD:
```json
{
  "metadata": {
    "project_name": "Order Management System",
    "project_id": "com.example.order_management",
    "version": "1.0.0"
  },
  "functional_requirements": [
    {
      "fr_id": "FR-001",
      "title": "Create Order",
      "description": "User creates an order with user ID and item list. Check user existence, product stock, calculate total price, deduct stock, create order record with status pending.",
      "priority": "high",
      "related_nfr_ids": [
        "NFR-001",
        "NFR-002"
      ],
      "depends_on": []
    },
    {
      "fr_id": "FR-002",
      "title": "Pay Order",
      "description": "User pays for an order. Check order exists and status is pending, check user balance, deduct balance, update order status to paid.",
      "priority": "high",
      "related_nfr_ids": [
        "NFR-001",
        "NFR-002"
      ],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-003",
      "title": "Ship Order",
      "description": "Ship an order. Check order exists and status is paid, update status to shipped.",
      "priority": "medium",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-002"
      ]
    },
    {
      "fr_id": "FR-004",
      "title": "Complete Order",
      "description": "Complete an order. Check order exists and status is shipped, update status to completed.",
      "priority": "medium",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-003"
      ]
    },
    {
      "fr_id": "FR-005",
      "title": "Cancel Order",
      "description": "Cancel an order. Check order exists and status is pending or paid, restore product stock, refund balance if paid, update status to cancelled.",
      "priority": "high",
      "related_nfr_ids": [
        "NFR-001",
        "NFR-002"
      ],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-006",
      "title": "List Orders",
      "description": "List orders with optional filters by user and status. Display order details including items, total price, status, and creation time.",
      "priority": "medium",
      "related_nfr_ids": [],
      "depends_on": []
    },
    {
      "fr_id": "FR-007",
      "title": "Get User Orders",
      "description": "Get all orders for a specific user. Calculate total spent and count of orders per status.",
      "priority": "medium",
      "related_nfr_ids": [],
      "depends_on": []
    },
    {
      "fr_id": "FR-008",
      "title": "List Products",
      "description": "List products with info and current stock. Optionally filter low stock products.",
      "priority": "low",
      "related_nfr_ids": [],
      "depends_on": []
    }
  ],
  "non_functional_requirements": [
    {
      "nfr_id": "NFR-001",
      "category": "reliability",
      "description": "Balance and stock must be consistent across operations (deduction and restoration)."
    },
    {
      "nfr_id": "NFR-002",
      "category": "reliability",
      "description": "Order status transitions must follow correct flow: pending -> paid -> shipped -> completed, with cancellation allowed from pending or paid."
    }
  ],
  "acceptance_criteria": [
    {
      "ac_id": "AC-001",
      "description": "Create order with valid user and sufficient stock succeeds, stock deducted, order created with status pending.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-001"
      ]
    },
    {
      "ac_id": "AC-002",
      "description": "Create order with insufficient stock fails with error message.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-001"
      ]
    },
    {
      "ac_id": "AC-003",
      "description": "Pay order with sufficient balance succeeds, balance deducted, status becomes paid.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-002"
      ]
    },
    {
      "ac_id": "AC-004",
      "description": "Pay order with insufficient balance fails with error message.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-002"
      ]
    },
    {
      "ac_id": "AC-005",
      "description": "Cancel pending order restores stock and no refund.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-005"
      ]
    },
    {
      "ac_id": "AC-006",
      "description": "Cancel paid order restores stock and refunds balance.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-005"
      ]
    },
    {
      "ac_id": "AC-007",
      "description": "Ship order only from paid status.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-003"
      ]
    },
    {
      "ac_id": "AC-008",
      "description": "Complete order only from shipped status.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-004"
      ]
    }
  ],
  "technical_constraints": {
    "storage": {
      "type": "memory",
      "details": "Three independent in-memory data sources: users, products, orders."
    },
    "concurrency": {
      "model": "single-user",
      "auth_required": false
    },
    "ui": {
      "type": "api",
      "details": "Function call interface manage_order(command, order_data)"
    },
    "language": "Python"
  },
  "glossary": {
    "order": "A record of a purchase transaction containing user, items, total price, status, and creation time.",
    "pending": "Initial order status after creation, awaiting payment.",
    "paid": "Order status after successful payment.",
    "shipped": "Order status after shipment.",
    "completed": "Order status after completion.",
    "cancelled": "Order status after cancellation.",
    "balance": "User's account balance used for payments.",
    "stock": "Available quantity of a product."
  },
  "global_state_sources": [
    {
      "source_id": "users",
      "type": "dict",
      "description": "Stores user information keyed by user_id.",
      "initial_state": {
        "1": {
          "user_id": 1,
          "name": "张三",
          "email": "zhang@test.com",
          "balance": 500.0
        },
        "2": {
          "user_id": 2,
          "name": "李四",
          "email": "li@test.com",
          "balance": 300.0
        },
        "3": {
          "user_id": 3,
          "name": "王五",
          "email": "wang@test.com",
          "balance": 100.0
        }
      },
      "item_schema": {
        "user_id": "int",
        "name": "str",
        "email": "str",
        "balance": "float"
      }
    },
    {
      "source_id": "products",
      "type": "dict",
      "description": "Stores product information keyed by product_id.",
      "initial_state": {
        "1": {
          "product_id": 1,
          "name": "手机",
          "price": 999.0,
          "stock": 10
        },
        "2": {
          "product_id": 2,
          "name": "耳机",
          "price": 99.9,
          "stock": 20
        },
        "3": {
          "product_id": 3,
          "name": "充电器",
          "price": 49.9,
          "stock": 50
        },
        "4": {
          "product_id": 4,
          "name": "数据线",
          "price": 19.9,
          "stock": 100
        },
        "5": {
          "product_id": 5,
          "name": "手机壳",
          "price": 29.9,
          "stock": 30
        }
      },
      "item_schema": {
        "product_id": "int",
        "name": "str",
        "price": "float",
        "stock": "int"
      }
    },
    {
      "source_id": "orders",
      "type": "dict",
      "description": "Stores order records keyed by order_id.",
      "initial_state": {},
      "item_schema": {
        "order_id": "int",
        "user_id": "int",
        "items": "list",
        "total_price": "float",
        "status": "str",
        "created_at": "str"
      }
    }
  ],
  "input_spec": {
    "format": "json",
    "description": "Input is a JSON object with command and order_data fields. The function manage_order(command, order_data) is called with these parameters.",
    "schema": {
      "command": "string - one of create_order, pay_order, ship_order, complete_order, cancel_order, list_orders, get_user_orders, list_products",
      "order_data": "object - contains fields depending on command: user_id (int), order_id (int), items (list of {product_id, quantity}), status_filter (str), user_filter (int), low_stock (bool)"
    },
    "examples": [
      {
        "command": "create_order",
        "order_data": {
          "user_id": 1,
          "items": [
            {
              "product_id": 2,
              "quantity": 2
            }
          ]
        }
      }
    ]
  },
  "output_spec": {
    "format": "json",
    "description": "Output is a JSON object with success, message, and data fields.",
    "schema": {
      "success": "boolean",
      "message": "string - human-readable result message",
      "data": "object - contains command-specific data"
    },
    "examples": [
      {
        "success": true,
        "message": "订单创建成功",
        "data": {
          "order_id": 1,
          "total_price": 199.8
        }
      }
    ]
  }
}
```

Remember:
- Choose storage model from: dict, list, in_memory_table
- Choose operations from: get, list, create, update, delete, exists
- Do NOT create business action interfaces like pay_order or ship_order
- Create only low-level CRUD interfaces
- Every resource needs at least a get interface
